VALUES
  (gen_random_uuid()::text, 'DIRECTOR', 'I', 'I.1.1', 'Стратегическото планиране е съобразено с областната и общинската стратегии за развитие на образованието и отчита спецификата на институцията. Стратегията за развитие и планът за действие и финансиране към нея се актуализират при необходимост.', 1, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'I', 'I.1.2', 'Оперативното годишно планиране е изготвено на база стратегическото планиране и сравнителен анализ на дейността на институцията и на постигнатите от децата/учениците резултати от образователния процес.', 2, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'I', 'I.2.1', 'Създаден е позитивен организационен климат за сътрудничество, ефективна комуникация и екип за подкрепа за личностно развитие. Прилага се компетентностният подход в работата при придобиване на ключови компетентности от децата/учениците съгласно чл. 77, ал. 1 от ЗПУО.', 3, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'I', 'I.2.2', 'Осигурена е обща и допълнителна подкрепа на деца/ученици от уязвими социални групи, със слаби резултати, в риск, със специални образователни потребности, с изявени дарби, с хронични заболявания и се прилагат мерки за превенция и/или намаляване на негативни поведенчески прояви, както и ограничаване на отпадането от училище/задължителна подготвителна група.', 4, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'I', 'I.2.3', 'Прилагат се ефективни механизми за оценка на училищната готовност на децата, за диагностика на индивидуалните постижения на децата/учениците, на резултатите от образователния процес и на напредъка при формиране на ключови компетентности.', 5, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'I', 'I.2.4', 'Създадена е оптимална организационна структура за управление и за решаване на основни педагогически въпроси (ефективно работят педагогическият съвет, общественият съвет, настоятелството, ученическото самоуправление, постоянни и временни комисии и др.).', 6, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'I', 'I.2.5', 'Изпълняват се дейности и процедури за вътрешна оценка на качеството на предоставяното образование – резултатите от самооценяването се използват в процеса на планиране.', 7, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'I', 'I.3.1', 'Създадена е оптимална организация за контрол по спазването и прилагането на държавните образователни стандарти, делегирани са правомощия за контролна дейност на заместник-директори.', 8, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'I', 'I.3.2', 'Осъществява се ефективен педагогически и административен контрол на дейностите и процесите в институцията, изготвя се анализ на получените резултати и при направени препоръки се осъществява последващ контрол, като дейността се документира.', 9, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'II', 'II.1', 'Създадена е ефективна организация на труда, разработени са вътрешни правила за подбор, назначаване, съкращаване, възнаграждения, поощрения и награди.', 10, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'II', 'II.2', 'Създадена е оптимална организационна структура за управление на отделните нива (екип за подкрепа за личностно развитие на ученика/детето, обществен съвет, настоятелство, постоянни и временни комисии, родителски съвети, класни съвети, ученическо самоуправление и др.).', 11, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'II', 'II.3', 'Осигурено е законосъобразно, ефективно и прозрачно разходване и отчитане на финансовите средства в определените срокове и пред определените инстанции. Функционира механизъм за финансово управление и контрол. Няма просрочени задължения.', 12, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'II', 'II.4', 'Осигурено е ефективно използване на създадената физическа среда със здравословни и безопасни условия на обучение, възпитание, социализация и труд.', 13, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'II', 'II.5', 'Създадени са организационни условия и е осигурена финансова подкрепа за повишаване на квалификацията на педагогическите специалисти с цел организационна и методическа подкрепа, професионално усъвършенстване и кариерно развитие. Създадени са условия за наставничество. Насърчава се новаторството и екипът се стимулира към иновации.', 14, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'II', 'II.6', 'Участие във форми на вътрешноинституционална квалификация, легитимирано със задължителните академични часове за периода на атестиране.', 15, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'II', 'II.7', 'Оценява собственото си професионално развитие, преценява необходимостта от повишаване на квалификацията си и се включва в квалификационни форми, свързани с целите на институцията или професионалната му област, и има задължителните за атестационния период квалификационни кредити.', 16, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'III', 'III.1', 'Познава и прилага действащата нормативна уредба в областта на предучилищното и училищното образование, на професионалното образование, на трудовото законодателство и социалното осигуряване и др., свързани с управлението и функционирането на институцията.', 17, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'III', 'III.2', 'Оказва съдействие на контролни органи и институции при осъществяване на контрол и инспектиране.', 18, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'IV', 'IV.1', 'Изградени са и се поддържат партньорски отношения чрез съвместни дейности с обществения съвет, училищното настоятелство, социалните партньори, други институции в образователната система, териториалните органи на изпълнителната власт, органите на местното самоуправление, неправителствени организации, висши училища и др. Отчита изпълнението на бюджета, на планираните дейности и постиженията на институцията пред педагогическия съвет, обществения съвет, общото събрание, включително чрез интернет страницата на институцията.', 19, NULL, now(), now()),
  (gen_random_uuid()::text, 'DIRECTOR', 'IV', 'IV.2', 'Осъществява се сътрудничество и взаимодействие с родителите за информирането им относно образованието на децата им. Осигурени са възможности за включване на родителите като участници в образователния процес в организираните от институцията дейности, както и за участие в обществения съвет. Участие в дейността на национални, областни, общински комисии, свързани с разработване и изпълнение на основни образователни политики или проекти.', 20, NULL, now(), now())
ON CONFLICT ("cardType", "questionCode")
DO UPDATE SET
  "sectionRoman" = EXCLUDED."sectionRoman",
  "prompt" = EXCLUDED."prompt",
  "displayOrder" = EXCLUDED."displayOrder",
  "updatedAt" = now();

